class CheckoutStep1View(View):
    """Paso 1: Selección de fechas"""
    template_name = 'reservations/checkout_step1.html'

    def get(self, request):
        cesta = get_or_create_cart(request)
        if not cesta.lineas.exists():
            messages.error(request, 'Tu cesta está vacía. Añade barcos antes de continuar.')
            return redirect('cart:view')

        form = CheckoutStep1Form()
        return render(request, self.template_name, {'form': form})

    def post(self, request):
        cesta = get_or_create_cart(request)
        if not cesta.lineas.exists():
            messages.error(request, 'Tu cesta está vacía.')
            return redirect('cart:view')

        form = CheckoutStep1Form(request.POST)
        if form.is_valid():
            request.session['checkout_fecha_inicio'] = form.cleaned_data['fecha_inicio'].isoformat()
            request.session['checkout_fecha_fin'] = form.cleaned_data['fecha_fin'].isoformat()
            return redirect('reservations:checkout_step2')

        return render(request, self.template_name, {'form': form})


class CheckoutStep2View(View):
    """Paso 2: Datos de contacto"""
    template_name = 'reservations/checkout_step2.html'

    def get(self, request):
        if 'checkout_fecha_inicio' not in request.session:
            messages.error(request, 'Por favor, completa el paso 1 primero.')
            return redirect('reservations:checkout_step1')

        form = CheckoutStep2Form()
        if request.user.is_authenticated:
            form.fields['nombre_contacto'].initial = f"{request.user.first_name} {request.user.last_name}".strip()
            form.fields['email_contacto'].initial = request.user.email

        return render(request, self.template_name, {'form': form})

    def post(self, request):
        if 'checkout_fecha_inicio' not in request.session:
            messages.error(request, 'Por favor, completa el paso 1 primero.')
            return redirect('reservations:checkout_step1')

        form = CheckoutStep2Form(request.POST)
        if form.is_valid():
            request.session['checkout_nombre_contacto'] = form.cleaned_data['nombre_contacto']
            request.session['checkout_email_contacto'] = form.cleaned_data['email_contacto']
            request.session['checkout_telefono_contacto'] = form.cleaned_data['telefono_contacto']
            return redirect('reservations:checkout_step3')

        return render(request, self.template_name, {'form': form})


class CheckoutStep3View(View):
    """Paso 3: Método de pago y confirmación"""
    template_name = 'reservations/checkout_step3.html'

    def get(self, request):
        if 'checkout_email_contacto' not in request.session:
            messages.error(request, 'Por favor, completa los pasos anteriores primero.')
            return redirect('reservations:checkout_step1')

        cesta = get_or_create_cart(request)
        if not cesta.lineas.exists():
            messages.error(request, 'Tu cesta está vacía.')
            return redirect('cart:view')

        # Calcular totales
        fecha_inicio = datetime.fromisoformat(request.session['checkout_fecha_inicio']).date()
        fecha_fin = datetime.fromisoformat(request.session['checkout_fecha_fin']).date()
        dias = (fecha_fin - fecha_inicio).days

        importe_base = Decimal('0')
        tasa_combustible = Decimal('0')

        for linea in cesta.lineas.all():
            precio_linea = linea.barco.precio_dia * linea.cantidad * dias
            importe_base += precio_linea

            # Aplicar tasa de combustible si no es velero
            if linea.barco.categoria.nombre.lower() != 'velero':
                tasa_combustible += Decimal('50') * linea.cantidad * dias

        importe_total = importe_base + tasa_combustible

        form = CheckoutStep3Form()
        context = {
            'form': form,
            'fecha_inicio': fecha_inicio,
            'fecha_fin': fecha_fin,
            'dias': dias,
            'importe_base': importe_base,
            'tasa_combustible': tasa_combustible,
            'importe_total': importe_total,
            'lineas': cesta.lineas.all(),
        }
        return render(request, self.template_name, context)

    def post(self, request):
        if 'checkout_email_contacto' not in request.session:
            messages.error(request, 'Por favor, completa los pasos anteriores primero.')
            return redirect('reservations:checkout_step1')

        cesta = get_or_create_cart(request)
        if not cesta.lineas.exists():
            messages.error(request, 'Tu cesta está vacía.')
            return redirect('cart:view')

        form = CheckoutStep3Form(request.POST)
        if form.is_valid():
            metodo_pago = form.cleaned_data['metodo_pago']

            # Calcular totales
            fecha_inicio = datetime.fromisoformat(request.session['checkout_fecha_inicio']).date()
            fecha_fin = datetime.fromisoformat(request.session['checkout_fecha_fin']).date()
            dias = (fecha_fin - fecha_inicio).days

            importe_base = Decimal('0')
            tasa_combustible = Decimal('0')

            for linea in cesta.lineas.all():
                precio_linea = linea.barco.precio_dia * linea.cantidad * dias
                importe_base += precio_linea

                if linea.barco.categoria.nombre.lower() != 'velero':
                    tasa_combustible += Decimal('50') * linea.cantidad * dias

            importe_total = importe_base + tasa_combustible

            # Crear reserva
            with transaction.atomic():
                reserva = Reserva.objects.create(
                    codigo_seguimiento=str(uuid.uuid4())[:32],
                    cliente=request.user if request.user.is_authenticated else None,
                    email_contacto=request.session['checkout_email_contacto'],
                    nombre_contacto=request.session['checkout_nombre_contacto'],
                    telefono_contacto=request.session.get('checkout_telefono_contacto', ''),
                    fecha_inicio=fecha_inicio,
                    fecha_fin=fecha_fin,
                    importe_base=importe_base,
                    tasa_combustible=tasa_combustible,
                    importe_total=importe_total,
                    metodo_pago=metodo_pago,
                    estado='PENDIENTE_DE_PAGO',
                )

                # Crear líneas de reserva
                for linea_cesta in cesta.lineas.all():
                    LineaReserva.objects.create(
                        reserva=reserva,
                        barco=linea_cesta.barco,
                        cantidad=linea_cesta.cantidad,
                        precio_unitario_dia=linea_cesta.barco.precio_dia,
                    )

                # Enviar correo de confirmación
                self._enviar_confirmacion(reserva)

                # Limpiar sesión y cesta
                for key in list(request.session.keys()):
                    if key.startswith('checkout_'):
                        del request.session[key]
                cesta.lineas.all().delete()

            # Redirigir según método de pago
            if metodo_pago == 'PAYPAL':
                return redirect('reservations:paypal_callback', codigo=reserva.codigo_seguimiento)
            else:
                return redirect('reservations:confirmation', codigo=reserva.codigo_seguimiento)

        # Recalcular contexto si hay errores
        fecha_inicio = datetime.fromisoformat(request.session['checkout_fecha_inicio']).date()
        fecha_fin = datetime.fromisoformat(request.session['checkout_fecha_fin']).date()
        dias = (fecha_fin - fecha_inicio).days

        importe_base = Decimal('0')
        tasa_combustible = Decimal('0')

        for linea in cesta.lineas.all():
            precio_linea = linea.barco.precio_dia * linea.cantidad * dias
            importe_base += precio_linea

            if linea.barco.categoria.nombre.lower() != 'velero':
                tasa_combustible += Decimal('50') * linea.cantidad * dias

        importe_total = importe_base + tasa_combustible

        context = {
            'form': form,
            'fecha_inicio': fecha_inicio,
            'fecha_fin': fecha_fin,
            'dias': dias,
            'importe_base': importe_base,
            'tasa_combustible': tasa_combustible,
            'importe_total': importe_total,
            'lineas': cesta.lineas.all(),
        }
        return render(request, self.template_name, context)

    def _enviar_confirmacion(self, reserva):
        """Envía correo de confirmación de reserva"""
        asunto = f'Confirmación de Reserva - {reserva.codigo_seguimiento}'

        lineas_texto = ''
        for linea in reserva.lineas.all():
            lineas_texto += f'- {linea.cantidad}x {linea.barco.nombre} @ {linea.precio_unitario_dia}€/día\n'

        mensaje = f"""Estimado {reserva.nombre_contacto},

Tu reserva ha sido confirmada exitosamente.

Datos de la Reserva:
- Código de Seguimiento: {reserva.codigo_seguimiento}
- Fecha de Inicio: {reserva.fecha_inicio}
- Fecha de Fin: {reserva.fecha_fin}
- Barcos:
{lineas_texto}
- Importe Base: {reserva.importe_base}€
- Tasa de Combustible: {reserva.tasa_combustible}€
- Total: {reserva.importe_total}€
- Método de Pago: {reserva.get_metodo_pago_display()}

Puedes seguir el estado de tu reserva en: {settings.SITE_URL}/reserva/seguimiento/?codigo={reserva.codigo_seguimiento}

Gracias por confiar en Hundidos.
"""

        try:
            send_mail(
                asunto,
                mensaje,
                settings.DEFAULT_FROM_EMAIL,
                [reserva.email_contacto],
                fail_silently=False,
            )
        except Exception as e:
            print(f'Error enviando correo: {e}')


class ConfirmationView(View):
    """Vista de confirmación de reserva"""
    template_name = 'reservations/confirmation.html'

    def get(self, request):
        codigo = request.GET.get('codigo')
        reserva = get_object_or_404(Reserva, codigo_seguimiento=codigo)

        return render(request, self.template_name, {'reserva': reserva})


class TrackingView(View):
    """Vista de seguimiento de reserva"""
    template_name = 'reservations/tracking.html'

    def get(self, request):
        codigo = request.GET.get('codigo')
        if not codigo:
            messages.error(request, 'Código de seguimiento no proporcionado.')
            return redirect('home')

        reserva = get_object_or_404(Reserva, codigo_seguimiento=codigo)
        return render(request, self.template_name, {'reserva': reserva})


class CancelReservationView(View):
    """Vista para cancelar una reserva"""

    def post(self, request, codigo):
        reserva = get_object_or_404(Reserva, codigo_seguimiento=codigo)

        # Solo se puede cancelar si está en estado PENDIENTE_DE_PAGO
        if reserva.estado != 'PENDIENTE_DE_PAGO':
            messages.error(request, 'Solo se pueden cancelar reservas pendientes de pago.')
            return redirect('reservations:tracking', codigo=codigo)

        # Eliminar la reserva
        reserva.delete()

        # Enviar correo de cancelación
        self._enviar_cancelacion(codigo, reserva.nombre_contacto, reserva.email_contacto)

        messages.success(request, 'Reserva cancelada correctamente.')
        return redirect('home')

    def _enviar_cancelacion(self, codigo, nombre, email):
        """Envía correo de confirmación de cancelación"""
        asunto = f'Cancelación de Reserva - {codigo}'

        mensaje = f"""Estimado {nombre},

Tu reserva ha sido cancelada correctamente.

Código de Seguimiento: {codigo}

Si tienes alguna pregunta, no dudes en contactarnos.

Gracias por usar Hundidos.
"""

        try:
            send_mail(
                asunto,
                mensaje,
                settings.DEFAULT_FROM_EMAIL,
                [email],
                fail_silently=False,
            )
        except Exception as e:
            print(f'Error enviando correo de cancelación: {e}')


