class PayPalCallbackView(View):
    """Vista de callback de PayPal"""
    template_name = 'reservations/confirmation.html'

    def get(self, request):
        codigo = request.GET.get('codigo')
        reserva = get_object_or_404(Reserva, codigo_seguimiento=codigo)

        # En un entorno real, aquí se verificaría la transacción con PayPal
        # Por ahora, simplemente marcamos como pagado
        reserva.estado = 'PAGADO'
        reserva.save()

        messages.success(request, 'Pago procesado correctamente.')
        return render(request, self.template_name, {'reserva': reserva})

    def post(self, request):
        # Manejo de IPN de PayPal
        return self.get(request)

